arguments.prompt:
Implement a multi-step job application wizard in this Blazor Web App at /tmp/sv-7e4e40c1e5d34c599289034a9ea57a58.

The app uses per-page Interactive Server mode. The layout (MainLayout) renders statically while each wizard page renders interactively with `@rendermode InteractiveServer`.

## Architecture

The key challenge: per-page interactivity means each page navigation creates a new circuit, so scoped services don't persist across navigations. The static layout can't use `<CascadingValue>` to reach interactive children.

**Solution:**
1. A **singleton** `WizardStateStore` service with a `ConcurrentDictionary<string, WizardState>` keyed by a session cookie value. This persists wizard data across page navigations (circuit changes).
2. A cookie middleware that sets a `WizardSessionId` cookie if not present (using a GUID).
3. A **scoped** `WizardSession` service that captures the session ID from `IHttpContextAccessor` on first access and provides convenient read/write access to the store.
4. The static `MainLayout` can access `IHttpContextAccessor` and `WizardStateStore` directly to determine progress (it renders via static SSR, so HttpContext is always available).
5. Each interactive page injects `WizardSession` to read/write step data. The session ID is captured during the prerender phase of `OnInitialized` when HttpContext is available.

## Files to create/modify

### 1. Create `Models/WizardState.cs`
Namespace: `sv_7e4e40c1e5d34c599289034a9ea57a58.Models`

```csharp
namespace sv_7e4e40c1e5d34c599289034a9ea57a58.Models;

public class WizardState
{
    public PersonalInfo PersonalInfo { get; set; } = new();
    public ExperienceInfo Experience { get; set; } = new();
    public ReferencesInfo References { get; set; } = new();
    public HashSet<int> CompletedSteps { get; set; } = [];
}

public class PersonalInfo
{
    public string Name { get; set; } = "";
    public string Email { get; set; } = "";
}

public class ExperienceInfo
{
    public List<JobEntry> Jobs { get; set; } = [];
}

public class JobEntry
{
    public string Company { get; set; } = "";
    public string Title { get; set; } = "";
    public string Duration { get; set; } = "";
}

public class ReferencesInfo
{
    public List<ReferenceContact> Contacts { get; set; } = [];
}

public class ReferenceContact
{
    public string Name { get; set; } = "";
    public string Email { get; set; } = "";
    public string Relationship { get; set; } = "";
}
```

### 2. Create `Services/WizardStateStore.cs`
Namespace: `sv_7e4e40c1e5d34c599289034a9ea57a58.Services`

```csharp
using System.Collections.Concurrent;
using sv_7e4e40c1e5d34c599289034a9ea57a58.Models;

namespace sv_7e4e40c1e5d34c599289034a9ea57a58.Services;

// Singleton service that holds wizard state keyed by session ID.
// Survives circuit disposal so data persists across page navigations
// in per-page interactive server mode.
public class WizardStateStore
{
    private readonly ConcurrentDictionary<string, WizardState> _states = new();

    public WizardState GetOrCreate(string sessionId)
    {
        return _states.GetOrAdd(sessionId, _ => new WizardState());
    }

    public void Remove(string sessionId)
    {
        _states.TryRemove(sessionId, out _);
    }
}
```

### 3. Create `Services/WizardSession.cs`
Namespace: `sv_7e4e40c1e5d34c599289034a9ea57a58.Services`

```csharp
using sv_7e4e40c1e5d34c599289034a9ea57a58.Models;

namespace sv_7e4e40c1e5d34c599289034a9ea57a58.Services;

// Scoped service that captures the session ID from HttpContext during
// the prerender phase and provides access to the wizard state store.
public class WizardSession
{
    private readonly WizardStateStore _store;
    private readonly IHttpContextAccessor _httpContextAccessor;
    private string? _sessionId;

    public WizardSession(WizardStateStore store, IHttpContextAccessor httpContextAccessor)
    {
        _store = store;
        _httpContextAccessor = httpContextAccessor;
    }

    private string SessionId
    {
        get
        {
            if (_sessionId is null)
            {
                var httpContext = _httpContextAccessor.HttpContext;
                _sessionId = httpContext?.Request.Cookies["WizardSessionId"];
            }
            return _sessionId ?? throw new InvalidOperationException(
                "WizardSessionId cookie not found. Ensure the session middleware is configured.");
        }
    }

    public WizardState State => _store.GetOrCreate(SessionId);
}
```

### 4. Modify `Program.cs`

Add services and middleware. The final file should be:

```csharp
using sv_7e4e40c1e5d34c599289034a9ea57a58.Components;
using sv_7e4e40c1e5d34c599289034a9ea57a58.Services;

var builder = WebApplication.CreateBuilder(args);

// Add services to the container.
builder.Services.AddRazorComponents()
    .AddInteractiveServerComponents();

builder.Services.AddHttpContextAccessor();
builder.Services.AddSingleton<WizardStateStore>();
builder.Services.AddScoped<WizardSession>();

var app = builder.Build();

// Configure the HTTP request pipeline.
if (!app.Environment.IsDevelopment())
{
    app.UseExceptionHandler("/Error", createScopeForErrors: true);
}
app.UseStatusCodePagesWithReExecute("/not-found", createScopeForStatusCodePages: true);

// Set a session cookie for wizard state tracking
app.Use(async (context, next) =>
{
    if (!context.Request.Cookies.ContainsKey("WizardSessionId"))
    {
        context.Response.Cookies.Append("WizardSessionId", Guid.NewGuid().ToString(), new CookieOptions
        {
            HttpOnly = true,
            SameSite = SameSiteMode.Strict,
            IsEssential = true
        });
    }
    await next();
});

app.UseAntiforgery();

app.MapStaticAssets();
app.MapRazorComponents<App>()
    .AddInteractiveServerRenderMode();

app.Run();
```

### 5. Create `Components/Pages/Apply/PersonalInfoStep.razor`

```razor
@page "/apply/personal-info"
@rendermode InteractiveServer
@using sv_7e4e40c1e5d34c599289034a9ea57a58.Services
@inject WizardSession Wizard
@inject NavigationManager Nav

<PageTitle>Apply - Personal Info</PageTitle>

<h1>Step 1: Personal Information</h1>

<div class="mb-3">
    <label class="form-label">Full Name</label>
    <input class="form-control" @bind="Wizard.State.PersonalInfo.Name" />
</div>

<div class="mb-3">
    <label class="form-label">Email Address</label>
    <input class="form-control" type="email" @bind="Wizard.State.PersonalInfo.Email" />
</div>

<div class="d-flex justify-content-end">
    <button class="btn btn-primary" @onclick="Next">Next →</button>
</div>

@code {
    private void Next()
    {
        Wizard.State.CompletedSteps.Add(1);
        Nav.NavigateTo("/apply/experience");
    }
}
```

### 6. Create `Components/Pages/Apply/ExperienceStep.razor`

```razor
@page "/apply/experience"
@rendermode InteractiveServer
@using sv_7e4e40c1e5d34c599289034a9ea57a58.Models
@using sv_7e4e40c1e5d34c599289034a9ea57a58.Services
@inject WizardSession Wizard
@inject NavigationManager Nav

<PageTitle>Apply - Experience</PageTitle>

<h1>Step 2: Work Experience</h1>

@foreach (var job in Wizard.State.Experience.Jobs)
{
    <div class="card mb-3 p-3">
        <div class="mb-2">
            <label class="form-label">Company</label>
            <input class="form-control" @bind="job.Company" />
        </div>
        <div class="mb-2">
            <label class="form-label">Job Title</label>
            <input class="form-control" @bind="job.Title" />
        </div>
        <div class="mb-2">
            <label class="form-label">Duration</label>
            <input class="form-control" @bind="job.Duration" />
        </div>
        <button class="btn btn-outline-danger btn-sm" @onclick="() => RemoveJob(job)">Remove</button>
    </div>
}

<button class="btn btn-outline-secondary mb-3" @onclick="AddJob">+ Add Job</button>

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="Back">← Back</button>
    <button class="btn btn-primary" @onclick="Next">Next →</button>
</div>

@code {
    private void AddJob()
    {
        Wizard.State.Experience.Jobs.Add(new JobEntry());
    }

    private void RemoveJob(JobEntry job)
    {
        Wizard.State.Experience.Jobs.Remove(job);
    }

    private void Back()
    {
        Nav.NavigateTo("/apply/personal-info");
    }

    private void Next()
    {
        Wizard.State.CompletedSteps.Add(2);
        Nav.NavigateTo("/apply/references");
    }
}
```

### 7. Create `Components/Pages/Apply/ReferencesStep.razor`

```razor
@page "/apply/references"
@rendermode InteractiveServer
@using sv_7e4e40c1e5d34c599289034a9ea57a58.Models
@using sv_7e4e40c1e5d34c599289034a9ea57a58.Services
@inject WizardSession Wizard
@inject NavigationManager Nav

<PageTitle>Apply - References</PageTitle>

<h1>Step 3: References</h1>

@foreach (var contact in Wizard.State.References.Contacts)
{
    <div class="card mb-3 p-3">
        <div class="mb-2">
            <label class="form-label">Name</label>
            <input class="form-control" @bind="contact.Name" />
        </div>
        <div class="mb-2">
            <label class="form-label">Email</label>
            <input class="form-control" type="email" @bind="contact.Email" />
        </div>
        <div class="mb-2">
            <label class="form-label">Relationship</label>
            <input class="form-control" @bind="contact.Relationship" />
        </div>
        <button class="btn btn-outline-danger btn-sm" @onclick="() => RemoveContact(contact)">Remove</button>
