### 3. Create `Services/WizardSession.cs`
Namespace: `sv_7e4e40c1e5d34c599289034a9ea57a58.Services`

```csharp
using sv_7e4e40c1e5d34c599289034a9ea57a58.Models;

namespace sv_7e4e40c1e5d34c599289034a9ea57a58.Services;

// Scoped service that captures the session ID from HttpContext during
// the prerender phase and provides access to the wizard state store.
public class WizardSession
{
    private readonly WizardStateStore _store;
    private readonly IHttpContextAccessor _httpContextAccessor;
    private string? _sessionId;

    public WizardSession(WizardStateStore store, IHttpContextAccessor httpContextAccessor)
    {
        _store = store;
        _httpContextAccessor = httpContextAccessor;
    }

    private string SessionId
    {
        get
        {
            if (_sessionId is null)
            {
                var httpContext = _httpContextAccessor.HttpContext;
                _sessionId = httpContext?.Request.Cookies["WizardSessionId"];
            }
            return _sessionId ?? throw new InvalidOperationException(
                "WizardSessionId cookie not found. Ensure the session middleware is configured.");
        }
    }

    public WizardState State => _store.GetOrCreate(SessionId);
}
```

