using sv_7e4e40c1e5d34c599289034a9ea57a58.Components;
using sv_7e4e40c1e5d34c599289034a9ea57a58.Services;

var builder = WebApplication.CreateBuilder(args);

// Add services to the container.
builder.Services.AddRazorComponents()
    .AddInteractiveServerComponents();

builder.Services.AddHttpContextAccessor();
builder.Services.AddSingleton<WizardStateStore>();
builder.Services.AddScoped<WizardSession>();

var app = builder.Build();

// Configure the HTTP request pipeline.
if (!app.Environment.IsDevelopment())
{
    app.UseExceptionHandler("/Error", createScopeForErrors: true);
}
app.UseStatusCodePagesWithReExecute("/not-found", createScopeForStatusCodePages: true);

// Set a session cookie for wizard state tracking
app.Use(async (context, next) =>
{
    if (!context.Request.Cookies.ContainsKey("WizardSessionId"))
    {
        context.Response.Cookies.Append("WizardSessionId", Guid.NewGuid().ToString(), new CookieOptions
        {
            HttpOnly = true,
            SameSite = SameSiteMode.Strict,
            IsEssential = true
        });
    }
    await next();
});

app.UseAntiforgery();

app.MapStaticAssets();
app.MapRazorComponents<App>()
    .AddInteractiveServerRenderMode();

app.Run();
