public class WizardState
{
    public PersonalInfo PersonalInfo { get; set; } = new();
    public ExperienceInfo Experience { get; set; } = new();
    public ReferencesInfo References { get; set; } = new();
    public HashSet<int> CompletedSteps { get; set; } = [];
}

public class PersonalInfo
{
    public string Name { get; set; } = "";
    public string Email { get; set; } = "";
}

public class ExperienceInfo
{
    public List<JobEntry> Jobs { get; set; } = [];
}

public class JobEntry
{
    public string Company { get; set; } = "";
    public string Title { get; set; } = "";
    public string Duration { get; set; } = "";
}

public class ReferencesInfo
{
    public List<ReferenceContact> Contacts { get; set; } = [];
}

public class ReferenceContact
{
    public string Name { get; set; } = "";
    public string Email { get; set; } = "";
    public string Relationship { get; set; } = "";
}

using System.Collections.Concurrent;
using sv_7e4e40c1e5d34c599289034a9ea57a58.Models;

namespace sv_7e4e40c1e5d34c599289034a9ea57a58.Services;

// Singleton service that holds wizard state keyed by session ID.
// Survives circuit disposal so data persists across page navigations
// in per-page interactive server mode.
public class WizardStateStore
{
    private readonly ConcurrentDictionary<string, WizardState> _states = new();

    public WizardState GetOrCreate(string sessionId)
    {
        return _states.GetOrAdd(sessionId, _ => new WizardState());
    }

    public void Remove(string sessionId)
    {
        _states.TryRemove(sessionId, out _);
    }
}

using sv_7e4e40c1e5d34c599289034a9ea57a58.Models;

namespace sv_7e4e40c1e5d34c599289034a9ea57a58.Services;

// Scoped service that captures the session ID from HttpContext during
// the prerender phase and provides access to the wizard state store.
public class WizardSession
{
    private readonly WizardStateStore _store;
    private readonly IHttpContextAccessor _httpContextAccessor;
    private string? _sessionId;

    public WizardSession(WizardStateStore store, IHttpContextAccessor httpContextAccessor)
    {
        _store = store;
        _httpContextAccessor = httpContextAccessor;
    }

    private string SessionId
    {
        get
        {
            if (_sessionId is null)
            {
                var httpContext = _httpContextAccessor.HttpContext;
                _sessionId = httpContext?.Request.Cookies["WizardSessionId"];
            }
            return _sessionId ?? throw new InvalidOperationException(
                "WizardSessionId cookie not found. Ensure the session middleware is configured.");
        }
    }

    public WizardState State => _store.GetOrCreate(SessionId);
}

