### 9. Modify `Components/Layout/MainLayout.razor`

The layout renders statically, so it has access to `HttpContext`. It reads the URL to determine the current step and accesses the `WizardStateStore` to see which steps are completed.

```razor
@inherits LayoutComponentBase
@using sv_7e4e40c1e5d34c599289034a9ea57a58.Services
@inject NavigationManager Nav
@inject WizardStateStore Store
@inject IHttpContextAccessor HttpContextAccessor

<div class="page">
    <div class="sidebar">
        <NavMenu />
    </div>

    <main>
        <div class="top-row px-4">
            @if (CurrentStep > 0)
            {
                <span class="me-3">Step @CurrentStep of 4</span>
                <div class="progress flex-grow-1" style="height: 8px;">
                    <div class="progress-bar" role="progressbar"
                         style="width: @(CurrentStep * 25)%"></div>
                </div>
            }
            else
            {
                <a href="https://learn.microsoft.com/aspnet/core/" target="_blank">About</a>
            }
        </div>

        @if (CurrentStep > 0)
        {
            <nav class="px-4 py-2 d-flex gap-3">
                @foreach (var step in Steps)
                {
                    var css = step.Number == CurrentStep ? "fw-bold text-primary"
                        : CompletedSteps.Contains(step.Number) ? "text-success"
                        : "text-muted";
                    <a href="@step.Url" class="@css text-decoration-none">
                        @(CompletedSteps.Contains(step.Number) ? "✓ " : "")@step.Label
                    </a>
                }
            </nav>
        }

        <article class="content px-4">
            @Body
        </article>
    </main>
</div>

<div id="blazor-error-ui" data-nosnippet>
    An unhandled error has occurred.
    <a href="." class="reload">Reload</a>
    <span class="dismiss">🗙</span>
</div>

@code {
    private static readonly (int Number, string Url, string Label)[] Steps =
    [
        (1, "/apply/personal-info", "Personal Info"),
        (2, "/apply/experience", "Experience"),
        (3, "/apply/references", "References"),
        (4, "/apply/review", "Review"),
    ];

    private int CurrentStep
    {
        get
        {
            var uri = new Uri(Nav.Uri).AbsolutePath;
            return uri switch
            {
                "/apply/personal-info" => 1,
                "/apply/experience" => 2,
                "/apply/references" => 3,
                "/apply/review" => 4,
                _ => 0
            };
        }
    }

    private HashSet<int> CompletedSteps
    {
        get
        {
            var sessionId = HttpContextAccessor.HttpContext?.Request.Cookies["WizardSessionId"];
            if (sessionId is null) return [];
            return Store.GetOrCreate(sessionId).CompletedSteps;
        }
    }
}
```

